CREATE OR REPLACE FUNCTION fpa_interest (as_memno char, ai_year bigint,ai_month bigint,ai_seq bigint,as_code char) RETURNS bigint AS $body$
DECLARE

  ldc_amount sc_kep_t_monthly_receive_det.money_amount%type;

BEGIN
    select sum(CASE WHEN trim(both keeping_type_code)=trim(both as_code) THEN interest  ELSE 0 END )
  into STRICT ldc_amount
  from sc_kep_t_monthly_receive_det
  where (membership_no = as_memno)
  and (receive_year = ai_year)
  and (receive_month = ai_month)
  and (seq_no = ai_seq)
  and (keeping_type_code = as_code);

  if coalesce(ldc_amount::text, '') = '' then ldc_amount := 0;end if;

  return coalesce(ldc_amount,0);
  return null;
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
